    if (!out) {
        return false;
    }
    archive_write_disk_set_options(out, flags);
// প্ৰতিটো প্ৰতিলিপি পঢ়ক আৰু নিষ্কাশন কৰক    while ((r = archive_read_next_header(src, &entry)) == ARCHIVE_OK) {
        // সম্পূৰ্ণ পথ সৃষ্টি কৰক        snprintf(full_path, sizeof(full_path), "%s/%s",
                dest_path, archive_entry_pathname(entry));
        archive_entry_set_pathname(entry, full_path);
